map "https://example.org/fhir/li-xinyang-interop-r4/StructureMap/v2-txa-to-documentreference" = "V2TXAToDocumentReference"

uses "https://example.org/fhir/li-xinyang-interop-r4/StructureDefinition/HITCV2TXA" alias V2TXA as source
uses "https://example.org/fhir/li-xinyang-interop-r4/StructureDefinition/hitc-canonical-document-reference" alias DocumentReference as target

group V2TXAToDocumentReference(source src : HITCV2TXA, target tgt : DocumentReference) {
  src.uniqueDocumentNumber as v -> tgt.identifier.value = copy(v) "documentIdentifier";
  src.uniqueDocumentNumber as v -> tgt.identifier.system = evaluate('https://example.org/fhir/sid/document') "identifierSystem";
  src.uniqueDocumentNumber as v -> tgt.status = evaluate('current') "currentStatus";
  src.documentType as v -> tgt.type.coding = copy(v) "documentType";
  src.activityDateTime as v -> tgt.date = copy(v) "documentDate";
  src.sourceUri as v -> tgt.content.attachment.url = copy(v) "documentUrl";
  src.sourceUri as v -> tgt.content.attachment.contentType = evaluate('application/octet-stream') "contentType";
}

// Draft and experimental. Reference resolution, source-system extension population, semantic reconciliation, UCUM normalization, temporal normalization, and validation are orchestrated outside this Phase 1 map unless explicitly shown.
